issue_body:
### Description

When using WebGPURenderer with multiple views (e.g., a Quad-view using PassNode), the ClippingContext for a ClippingGroup caches a stale viewMatrix. This causes clipping planes to "drift" or follow the camera in perspective views because the child context reuses the matrix from a previous view's camera. (First saw this issue in r177, when i upgraded to r180 it went away. came back again in r184.)

### Reproduction steps

1. Set up a Quad-view with WebGPU.
2. Add a ClippingGroup to the scene.
3. Orbit the perspective camera.
4. Observe the clipping plane translating with the camera movement.

Below patch in library fixed the issue for me
```patch
diff --git a/node_modules/three/src/renderers/common/ClippingContext.js b/node_modules/three/src/renderers/common/ClippingContext.js
index 1234567..abcdefg 100644
--- a/node_modules/three/src/renderers/common/ClippingContext.js
+++ b/node_modules/three/src/renderers/common/ClippingContext.js
@@ -152,6 +152,8 @@ class ClippingContext {
 	update( parentContext, clippingGroup ) {

+		this.viewMatrix = parentContext.viewMatrix;
+
 		let update = false;

 		if ( parentContext.version !== this.parentVersion ) {

diff --git a/node_modules/three/build/three.webgpu.js b/node_modules/three/build/three.webgpu.js
--- a/node_modules/three/build/three.webgpu.js
+++ b/node_modules/three/build/three.webgpu.js
@@ update ClippingContext.update in three.webgpu.js line ~55272 @@
+		this.viewMatrix = parentContext.viewMatrix;
 		let update = false;

diff --git a/node_modules/three/build/three.webgpu.nodes.js b/node_modules/three/build/three.webgpu.nodes.js
--- a/node_modules/three/build/three.webgpu.nodes.js
+++ b/node_modules/three/build/three.webgpu.nodes.js
@@ update ClippingContext.update in three.webgpu.nodes.js line ~55272 @@
+		this.viewMatrix = parentContext.viewMatrix;
 		let update = false;

# ROOT CAUSE:
# ClippingContext child is created once in a WeakMap keyed by ClippingGroup.
# Constructor sets: this.viewMatrix = parentContext.viewMatrix  (reference copy)
# updateGlobal() does: this.viewMatrix = camera.matrixWorldInverse  (reference REASSIGNMENT)
# After updateGlobal, parent.viewMatrix points to new camera — child.viewMatrix still
# points to the original camera from construction time.
# In quadview with 4 cameras sharing one RenderContext (same renderTarget attachment state),
# all views share one ClippingContext and one WeakMap. The child is created on first view
# render, and all subsequent views use that stale viewMatrix for projectPlanes().
# Fix: resync viewMatrix from parent at the top of every update() call.
```


### Code

```js
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

async function init() {

  // ── WebGPU availability check ──────────────────────────────────────────────
  if ( ! navigator.gpu ) {
    const el = document.createElement('div');
    el.id = 'no-webgpu';
    el.className = 'visible';
    el.innerHTML = '<span>WebGPU not supported in this browser.</span><span>Try Chrome 113+ or Edge 113+.</span>';
    document.body.appendChild( el );
    return;
  }

  // ── Renderer ───────────────────────────────────────────────────────────────
  const canvas = document.getElementById( 'canvas' );

  const renderer = new THREE.WebGPURenderer( { canvas, antialias: true } );
  await renderer.init();
  renderer.setPixelRatio( window.devicePixelRatio );
  renderer.setSize( window.innerWidth, window.innerHeight );
  renderer.autoClear = false; // we clear manually once per frame for split-viewport

  // ── Scene ──────────────────────────────────────────────────────────────────
  const scene = new THREE.Scene();
  scene.background = new THREE.Color( 0x141428 );

  // Green box — lives at X < 0, should ALWAYS be visible
  const greenBox = new THREE.Mesh(
    new THREE.BoxGeometry( 1.6, 1.6, 1.6 ),
    new THREE.MeshPhongMaterial( { color: 0x22dd66, emissive: 0x004422 } )
  );
  greenBox.position.set( -1.8, 0, 0 );

  // Red box — lives at X > 0, should ALWAYS be hidden (clipped by the plane)
  const redBox = new THREE.Mesh(
    new THREE.BoxGeometry( 1.6, 1.6, 1.6 ),
    new THREE.MeshPhongMaterial( { color: 0xff2222, emissive: 0x440000 } )
  );
  redBox.position.set( 1.8, 0, 0 );

  // ── ClippingGroup: discard X > 0, keep X ≤ 0 ──────────────────────────────
  const clipGroup = new THREE.ClippingGroup();
  clipGroup.clippingPlanes = [ new THREE.Plane( new THREE.Vector3( -1, 0, 0 ), 0 ) ];
  clipGroup.add( greenBox );
  clipGroup.add( redBox );
  scene.add( clipGroup );

  // Yellow wireframe rectangle marks the clip plane boundary (X = 0)
  const planeMarker = new THREE.LineLoop(
    new THREE.BufferGeometry().setFromPoints( [
      new THREE.Vector3( 0,  2.5, -4 ),
      new THREE.Vector3( 0, -2.5, -4 ),
      new THREE.Vector3( 0, -2.5,  4 ),
      new THREE.Vector3( 0,  2.5,  4 ),
    ] ),
    new THREE.LineBasicMaterial( { color: 0xffff00 } )
  );
  scene.add( planeMarker );

  // Grid floor
  const grid = new THREE.GridHelper( 12, 12, 0x334466, 0x222244 );
  grid.position.y = -2;
  scene.add( grid );

  // Lights
  scene.add( new THREE.AmbientLight( 0xffffff, 0.5 ) );
  const dirLight = new THREE.DirectionalLight( 0xffffff, 1.5 );
  dirLight.position.set( 5, 8, 5 );
  scene.add( dirLight );

  // ── Cameras ────────────────────────────────────────────────────────────────
  function halfW() { return window.innerWidth / 2; }
  function aspect() { return halfW() / window.innerHeight; }

  const orthoCamera = new THREE.OrthographicCamera(
    -5 * aspect(), 5 * aspect(), 5, -5, 0.1, 100
  );
  orthoCamera.position.set( 0, 4, 9 );
  orthoCamera.lookAt( 0, 0, 0 );

  const perspCamera = new THREE.PerspectiveCamera( 50, aspect(), 0.1, 100 );
  perspCamera.position.set( 0, 3, 9 );
  perspCamera.lookAt( 0, 0, 0 );

  const controls = new OrbitControls( perspCamera, canvas );
  controls.enableDamping = true;
  controls.dampingFactor = 0.08;
  // Restrict to pan/orbit only (no zoom needed to show the bug)
  controls.minDistance = 3;
  controls.maxDistance = 20;

  // ── Resize handling ────────────────────────────────────────────────────────
  window.addEventListener( 'resize', () => {
    renderer.setSize( window.innerWidth, window.innerHeight );

    const a = aspect();
    orthoCamera.left   = -5 * a;
    orthoCamera.right  =  5 * a;
    orthoCamera.updateProjectionMatrix();

    perspCamera.aspect = a;
    perspCamera.updateProjectionMatrix();
  } );

  // ── Render loop ────────────────────────────────────────────────────────────
  renderer.setAnimationLoop( () => {

    controls.update();

    const w2 = halfW();
    const h  = window.innerHeight;

    renderer.clear();
    renderer.setViewport( 0, 0, w2, h );
    renderer.setScissor( 0, 0, w2, h );
    renderer.setScissorTest( true );
    renderer.render( scene, orthoCamera );
    renderer.setViewport( w2, 0, w2, h );
    renderer.setScissor( w2, 0, w2, h );
    renderer.render( scene, perspCamera );

    renderer.setScissorTest( false );

  } );

}

init().catch( err => {
  console.error( err );
  alert( 'Initialisation error: ' + err.message );
} );

```


